fn greet(name: &str, age: u32) {
    println!("Hello {}, age {}", name, age);
}

fn main() {
    greet("Alice"); // Error: expected 2 arguments, found 1
    greet("Bob", 30, true); // Error: expected 2 arguments, found 3
}

fixes.code:
fn greet(name: &str, age: Option<u32>) {
    match age {
        Some(a) => println!("Hello {}, age {}", name, a),
        None => println!("Hello {}", name),
    }
}

greet("Alice", None);
greet("Bob", Some(30));

struct GreetingBuilder {
    name: String,
    age: Option<u32>,
}

impl GreetingBuilder {
    fn new(name: &str) -> Self {
        Self { name: name.into(), age: None }
    }
    fn age(mut self, age: u32) -> Self {
        self.age = Some(age);
        self
    }
    fn build(self) -> String {
        format!("Hello {}", self.name)
    }
}
